mapper.sql:
from aiw_ai_model_skill_binding b
where 1 = 1

    and b.model_biz_id = #{criteria.modelBizId}


    and b.model_code = #{criteria.modelCode}


    and b.skill_code = #{criteria.skillCode}


    and b.scenario_code = #{criteria.scenarioCode}


    and b.enabled = #{criteria.enabled}

mapper.select:
select *
from aiw_ai_model_skill_binding
where model_biz_id = #{modelBizId}
  and skill_biz_id = #{skillBizId}
  and scenario_code = #{scenarioCode}
limit 1

select b.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
